query:
{
  functionApps(
    where: {
      configs_SOME: {
        isDeprecated: { eq: true }
        OR: [
          { NOT: { nodeVersion: { eq: "" } } }
          { NOT: { pythonVersion: { eq: "" } } }
          { NOT: { javaVersion: { eq: "" } } }
          { NOT: { powerShellVersion: { eq: "" } } }
          { NOT: { netFrameworkVersion: { eq: "" } } }
          { NOT: { linuxFxVersion: { eq: "" } } }
        ]
      }
    }
  ) {
    ...AssetFragment
    configs {
      nodeVersion
      pythonVersion
      javaVersion
      powerShellVersion
      netFrameworkVersion
      linuxFxVersion
    }
  }
}
